import { CommonModule } from '@angular/common';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Component, OnInit } from '@angular/core';
import { FormsModule } from '@angular/forms';

type Role = 'STUDENT' | 'TEACHER' | 'HR' | 'ADMIN';
type Page = 'home' | 'jobs' | 'job-details' | 'login' | 'student' | 'teacher' | 'hr' | 'admin' | 'skill-test' | 'results' | 'admit-cards' | 'notifications' | 'resume' | 'chat' | 'connections';

interface User {
  id: number;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  role: Role;
  state: string;
}

interface Job {
  id: number;
  title: string;
  department: string;
  state: string;
  city: string;
  sector: string;
  salary: string;
  applicationFee: number;
  totalPositions: number;
  examStartDate: string;
  applicationDeadline: string;
  minSkillMarks: number;
  description: string;
  eligibility: string;
  status: string;
  sourceName?: string;
  sourceUrl?: string;
  applyUrl?: string;
  tags?: string[];
}

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  private readonly apiUrl = 'http://localhost:5000/api';

  page: Page = 'home';
  darkMode = false;
  mobileMenu = false;
  profileMenu = false;
  loading = false;
  message = '';
  source: any = null;

  user: User | null = null;
  token = localStorage.getItem('govjob_token');

  states = ['All India', 'Andhra Pradesh', 'Assam', 'Bihar', 'Delhi', 'Gujarat', 'Haryana', 'Karnataka', 'Kerala', 'Madhya Pradesh', 'Maharashtra', 'Odisha', 'Punjab', 'Rajasthan', 'Tamil Nadu', 'Telangana', 'Uttar Pradesh', 'Uttarakhand', 'West Bengal'];
  selectedState = 'All India';
  search = '';
  jobs: Job[] = [];
  selectedJob: Job | null = null;

  login = { identifier: 'student@govjob.in', password: 'Password@123', phone: '9876543210', otp: '', mode: 'password' };
  register = { firstName: '', lastName: '', email: '', phone: '', password: '', role: 'STUDENT' as Role, state: 'Delhi' };
  otpSent = false;

  applications: any[] = [];
  notifications: any[] = [];
  connections: any[] = [];
  messages: any[] = [];
  chatText = '';
  resume = { headline: 'UPSC aspirant | Public administration | Data handling', education: 'B.A. Political Science, Delhi University', skills: 'Reasoning, Quantitative Aptitude, MS Office, Governance', experience: 'Volunteer teacher for competitive exam foundation classes' };
  testAnswers: Record<number, string> = {};
  testResult: any = null;

  constructor(private http: HttpClient) {}

  ngOnInit(): void {
    this.restoreSession();
    this.loadJobs();
  }

  get authHeaders(): HttpHeaders {
    return new HttpHeaders(this.token ? { Authorization: `Bearer ${this.token}` } : {});
  }

  get filteredJobs(): Job[] {
    return this.jobs.filter((job) => {
      const stateMatch = this.selectedState === 'All India' || job.state === this.selectedState;
      const text = `${job.title} ${job.department} ${job.sector} ${job.city}`.toLowerCase();
      return stateMatch && text.includes(this.search.toLowerCase());
    });
  }

  get recommendedJobs(): Job[] {
    const score = this.testResult?.percentage ?? 72;
    return this.jobs.filter((job) => score >= job.minSkillMarks).slice(0, 4);
  }

  get stats(): any[] {
    return [
      { label: 'Open vacancies', value: this.jobs.reduce((sum, job) => sum + job.totalPositions, 0) },
      { label: 'Applications', value: this.applications.length },
      { label: 'Skill score', value: `${this.testResult?.percentage ?? 76}%` },
      { label: 'Unread alerts', value: this.notifications.filter((n) => !n.isRead).length }
    ];
  }

  navigate(page: Page): void {
    this.page = page;
    this.mobileMenu = false;
    this.message = '';
    if (page === 'jobs') this.loadJobs();
    if (page === 'notifications') this.loadNotifications();
    if (page === 'connections') this.loadConnections();
    if (page === 'chat') this.loadMessages();
    if (['student', 'teacher', 'hr', 'admin'].includes(page)) this.loadApplications();
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  async api<T>(method: 'GET' | 'POST' | 'PUT', path: string, body?: unknown): Promise<T> {
    const options = { headers: this.authHeaders, body };
    if (method === 'GET') return await this.http.get<T>(`${this.apiUrl}${path}`, { headers: this.authHeaders }).toPromise() as T;
    if (method === 'PUT') return await this.http.put<T>(`${this.apiUrl}${path}`, body, options).toPromise() as T;
    return await this.http.post<T>(`${this.apiUrl}${path}`, body, options).toPromise() as T;
  }

  async restoreSession(): Promise<void> {
    if (!this.token) return;
    try {
      const response: any = await this.api('GET', '/auth/me');
      this.user = response.user;
      this.loadNotifications();
    } catch {
      this.logout();
    }
  }

  async loadJobs(): Promise<void> {
    try {
      const response: any = await this.api('GET', `/jobs?state=${encodeURIComponent(this.selectedState === 'All India' ? '' : this.selectedState)}&search=${encodeURIComponent(this.search)}&limit=50`);
      this.jobs = response.jobs;
      this.source = response.source;
      this.selectedJob = this.selectedJob ?? this.jobs[0] ?? null;
    } catch {
      this.message = 'Backend is not reachable. Start the Node API on port 5000.';
    }
  }

  async syncSource(): Promise<void> {
    if (!this.user || !['HR', 'ADMIN'].includes(this.user.role)) {
      this.message = 'Login as HR or Admin to sync the Sarkari job source.';
      this.navigate('login');
      return;
    }
    this.loading = true;
    try {
      const response: any = await this.api('POST', '/source/sync', {});
      this.message = response.message;
      this.source = response.source;
      await this.loadJobs();
    } catch (error: any) {
      this.message = error?.error?.message ?? 'Source sync failed';
    } finally {
      this.loading = false;
    }
  }

  async passwordLogin(): Promise<void> {
    this.loading = true;
    try {
      const response: any = await this.api('POST', '/auth/login', { identifier: this.login.identifier, password: this.login.password });
      this.setSession(response);
      this.navigate(response.user.role === 'HR' ? 'hr' : response.user.role === 'ADMIN' ? 'admin' : 'student');
    } catch (error: any) {
      this.message = error?.error?.message ?? 'Login failed';
    } finally {
      this.loading = false;
    }
  }

  async registerUser(): Promise<void> {
    this.loading = true;
    try {
      const response: any = await this.api('POST', '/auth/register', this.register);
      this.setSession(response);
      this.navigate(this.register.role === 'HR' ? 'hr' : this.register.role === 'TEACHER' ? 'teacher' : 'student');
    } catch (error: any) {
      this.message = error?.error?.message ?? 'Registration failed';
    } finally {
      this.loading = false;
    }
  }

  async sendOtp(): Promise<void> {
    await this.api('POST', '/auth/send-otp', { phone: this.login.phone });
    this.otpSent = true;
    this.message = 'Demo OTP sent. Use 123456.';
  }

  async verifyOtp(): Promise<void> {
    const response: any = await this.api('POST', '/auth/verify-otp', { phone: this.login.phone, otp: this.login.otp || '123456' });
    this.setSession(response);
    this.navigate('student');
  }

  async socialLogin(provider: string): Promise<void> {
    const response: any = await this.api('POST', '/auth/social-login', { provider });
    this.setSession(response);
    this.navigate('student');
  }

  setSession(response: any): void {
    this.token = response.token;
    this.user = response.user;
    localStorage.setItem('govjob_token', response.token);
  }

  logout(): void {
    this.user = null;
    this.token = null;
    localStorage.removeItem('govjob_token');
    this.navigate('home');
  }

  viewJob(job: Job): void {
    this.selectedJob = job;
    this.navigate('job-details');
  }

  async apply(job: Job): Promise<void> {
    if (!this.user) {
      this.navigate('login');
      return;
    }
    const response: any = await this.api('POST', '/applications', { jobId: job.id });
    this.message = response.message;
    this.loadApplications();
  }

  async loadApplications(): Promise<void> {
    if (!this.user) return;
    const response: any = await this.api('GET', '/applications/me');
    this.applications = response.applications;
  }

  async createJob(): Promise<void> {
    const body = { title: 'State Revenue Inspector', department: 'Revenue Department', sector: 'Administration', state: this.user?.state ?? 'Delhi', city: 'Capital Region', salary: 'Level 6, Rs. 35,400 - 1,12,400', totalPositions: 124, applicationFee: 250, minSkillMarks: 60, description: 'Recruitment for revenue field administration, records, and citizen service delivery.', eligibility: 'Graduate degree with state language proficiency.' };
    const response: any = await this.api('POST', '/jobs', body);
    this.message = response.message;
    this.loadJobs();
  }

  async submitTest(): Promise<void> {
    const answers = Object.entries(this.testAnswers).map(([questionId, selectedAnswer]) => ({ questionId: Number(questionId), selectedAnswer }));
    const response: any = await this.api('POST', '/skill-tests/1/submit', { answers });
    this.testResult = response.result;
    this.message = 'Skill test submitted. Recommendations updated from your marks.';
  }

  async loadNotifications(): Promise<void> {
    if (!this.user) return;
    const response: any = await this.api('GET', '/notifications');
    this.notifications = response.notifications;
  }

  async loadConnections(): Promise<void> {
    if (!this.user) return;
    const response: any = await this.api('GET', '/hr-connections');
    this.connections = response.connections;
  }

  async requestConnection(): Promise<void> {
    const response: any = await this.api('POST', '/hr-connections', { hrId: 3, requestMessage: 'I want guidance for upcoming government recruitment.' });
    this.message = response.message;
    this.loadConnections();
  }

  async loadMessages(): Promise<void> {
    if (!this.user) return;
    const response: any = await this.api('GET', '/chat/messages/3');
    this.messages = response.messages;
  }

  async sendMessage(): Promise<void> {
    if (!this.chatText.trim()) return;
    await this.api('POST', '/chat/messages', { receiverId: 3, message: this.chatText });
    this.chatText = '';
    this.loadMessages();
  }
}
<main class="min-h-screen transition-colors" [class.dark]="darkMode">
  <div class="portal-shell">
    <header class="sticky top-0 z-40 border-b border-white/20 bg-white/80 backdrop-blur-2xl dark:bg-slate-950/80">
      <nav class="mx-auto flex max-w-7xl items-center justify-between px-4 py-3">
        <button class="brand" (click)="navigate('home')" aria-label="Home">
          <span class="brand-mark">IN</span>
          <span><b>GovCareer</b><small>National Job & Exam Network</small></span>
        </button>
        <div class="nav-links" [class.open]="mobileMenu">
          <button (click)="navigate('jobs')">Jobs</button>
          <button (click)="navigate('skill-test')">Skill Test</button>
          <button (click)="navigate('results')">Results</button>
          <button (click)="navigate('admit-cards')">Admit Cards</button>
          <button (click)="navigate('connections')">Network</button>
          <button (click)="navigate('chat')">Chat</button>
          <button *ngIf="user?.role === 'HR'" (click)="navigate('hr')">HR</button>
          <button *ngIf="user?.role === 'ADMIN'" (click)="navigate('admin')">Admin</button>
        </div>
        <div class="flex items-center gap-2">
          <button class="icon-btn" (click)="darkMode = !darkMode" [title]="darkMode ? 'Light mode' : 'Dark mode'">{{ darkMode ? '☀' : '◐' }}</button>
          <button *ngIf="!user" class="btn ghost" (click)="navigate('login')">Login</button>
          <button *ngIf="user" class="btn ghost" (click)="navigate(user.role === 'HR' ? 'hr' : user.role === 'ADMIN' ? 'admin' : 'student')">{{ user.firstName }}</button>
          <button *ngIf="user" class="btn primary" (click)="logout()">Logout</button>
          <button class="icon-btn md:hidden" (click)="mobileMenu = !mobileMenu">☰</button>
        </div>
      </nav>
    </header>

    <section *ngIf="message" class="mx-auto mt-4 max-w-7xl px-4">
      <div class="notice">{{ message }}</div>
    </section>

    <section *ngIf="page === 'home'" class="hero">
      <div class="hero-grid">
        <div class="hero-copy">
          <p class="eyebrow">Government recruitment, exams, networking, and preparation</p>
          <h1>Find verified Indian government jobs with exam intelligence built in.</h1>
          <p class="hero-text">Search by state, apply with one profile, take skill tests, track admit cards and results, connect with recruiters, and get AI-style job recommendations from your marks.</p>
          <div class="search-bar">
            <input [(ngModel)]="search" placeholder="Search SSC, railway, police, teacher, revenue..." (keyup.enter)="navigate('jobs'); loadJobs()">
            <select [(ngModel)]="selectedState" (change)="loadJobs()">
              <option *ngFor="let state of states">{{ state }}</option>
            </select>
            <button class="btn primary" (click)="navigate('jobs'); loadJobs()">Search Jobs</button>
          </div>
          <div class="hero-actions">
            <button class="btn primary" (click)="navigate('student')">Student Dashboard</button>
            <button class="btn secondary" (click)="navigate('hr')">Recruiter Workspace</button>
            <button class="btn ghost" (click)="navigate('resume')">Build Resume</button>
          </div>
        </div>
        <div class="insight-panel glass">
          <div class="panel-head"><span>Live recruitment radar</span><b>{{ filteredJobs.length }} active</b></div>
          <div class="state-map">
            <button *ngFor="let state of states.slice(1, 10)" (click)="selectedState = state; navigate('jobs'); loadJobs()">{{ state }}</button>
          </div>
          <div class="mini-feed" *ngFor="let job of jobs.slice(0, 3)">
            <span>{{ job.state }}</span>
            <strong>{{ job.title }}</strong>
            <small>{{ job.totalPositions }} posts · Fee ₹{{ job.applicationFee }}</small>
          </div>
        </div>
      </div>
    </section>

    <section *ngIf="page === 'jobs'" class="page">
      <div class="section-title"><p>Indeed-like search</p><h2>Government Jobs Listing</h2></div>
      <div class="filters glass">
        <input [(ngModel)]="search" placeholder="Search title, sector, department" (input)="loadJobs()">
        <select [(ngModel)]="selectedState" (change)="loadJobs()"><option *ngFor="let state of states">{{ state }}</option></select>
        <button class="btn primary" (click)="loadJobs()">Filter</button>
      </div>
      <div class="job-layout">
        <article class="job-card" *ngFor="let job of filteredJobs" (click)="viewJob(job)">
          <div><span class="tag">{{ job.state }}</span><span class="tag amber">Exam {{ job.examStartDate | date:'mediumDate' }}</span></div>
          <h3>{{ job.title }}</h3>
          <p>{{ job.department }} · {{ job.city }} · {{ job.sector }}</p>
          <div class="job-meta"><b>{{ job.salary }}</b><span>{{ job.totalPositions }} posts</span><span>Fee ₹{{ job.applicationFee }}</span></div>
          <button class="btn ghost">View Details</button>
        </article>
      </div>
    </section>

    <section *ngIf="page === 'job-details' && selectedJob" class="page detail-grid">
      <article class="glass detail-main">
        <span class="tag">{{ selectedJob.status }}</span>
        <h2>{{ selectedJob.title }}</h2>
        <p class="muted">{{ selectedJob.department }} · {{ selectedJob.city }}, {{ selectedJob.state }}</p>
        <p>{{ selectedJob.description }}</p>
        <div class="info-grid">
          <div><small>Salary</small><b>{{ selectedJob.salary }}</b></div>
          <div><small>Application Fee</small><b>₹{{ selectedJob.applicationFee }}</b></div>
          <div><small>Exam Date</small><b>{{ selectedJob.examStartDate | date:'mediumDate' }}</b></div>
          <div><small>Minimum Skill Marks</small><b>{{ selectedJob.minSkillMarks }}%</b></div>
        </div>
        <h3>Eligibility</h3>
        <p>{{ selectedJob.eligibility }}</p>
        <button class="btn primary" (click)="apply(selectedJob)">Apply Now</button>
      </article>
      <aside class="glass side-panel">
        <h3>Recommended from marks</h3>
        <div class="mini-feed" *ngFor="let job of recommendedJobs"><strong>{{ job.title }}</strong><small>{{ job.state }} · {{ job.minSkillMarks }}% cutoff</small></div>
      </aside>
    </section>

    <section *ngIf="page === 'login'" class="auth-page">
      <div class="auth-card glass">
        <div class="section-title left"><p>Secure access</p><h2>Login or Register</h2></div>
        <div class="tabs"><button [class.active]="login.mode === 'password'" (click)="login.mode = 'password'">Email / Mobile + Password</button><button [class.active]="login.mode === 'otp'" (click)="login.mode = 'otp'">Mobile OTP</button></div>
        <div *ngIf="login.mode === 'password'" class="form-grid">
          <input [(ngModel)]="login.identifier" placeholder="Email or mobile number">
          <input [(ngModel)]="login.password" placeholder="Password" type="password">
          <button class="btn primary" [disabled]="loading" (click)="passwordLogin()">Login</button>
        </div>
        <div *ngIf="login.mode === 'otp'" class="form-grid">
          <input [(ngModel)]="login.phone" placeholder="Mobile number">
          <button class="btn secondary" (click)="sendOtp()">Send OTP</button>
          <input [(ngModel)]="login.otp" placeholder="Enter OTP 123456">
          <button class="btn primary" (click)="verifyOtp()">Verify OTP</button>
        </div>
        <div class="social-row"><button (click)="socialLogin('google')">Google</button><button (click)="socialLogin('linkedin')">LinkedIn</button><button (click)="socialLogin('facebook')">Facebook</button></div>
      </div>
      <div class="auth-card glass">
        <div class="section-title left"><p>New account</p><h2>Create Profile</h2></div>
        <div class="form-grid two">
          <input [(ngModel)]="register.firstName" placeholder="First name">
          <input [(ngModel)]="register.lastName" placeholder="Last name">
          <input [(ngModel)]="register.email" placeholder="Email">
          <input [(ngModel)]="register.phone" placeholder="Mobile number">
          <input [(ngModel)]="register.password" placeholder="Password" type="password">
          <select [(ngModel)]="register.role"><option>STUDENT</option><option>TEACHER</option><option>HR</option><option>ADMIN</option></select>
          <select [(ngModel)]="register.state"><option *ngFor="let state of states.slice(1)">{{ state }}</option></select>
          <button class="btn primary" (click)="registerUser()">Register</button>
        </div>
      </div>
    </section>

    <section *ngIf="page === 'student' || page === 'teacher' || page === 'hr' || page === 'admin'" class="page">
      <div class="section-title"><p>{{ page }} workspace</p><h2>{{ page === 'student' ? 'Student Dashboard' : page === 'teacher' ? 'Teacher Dashboard' : page === 'hr' ? 'HR Dashboard' : 'Admin Panel' }}</h2></div>
      <div class="stats-grid"><div class="stat glass" *ngFor="let stat of stats"><small>{{ stat.label }}</small><b>{{ stat.value }}</b></div></div>
      <div class="dashboard-grid">
        <article class="glass">
          <h3>AI Job Recommendations</h3>
          <div class="mini-feed" *ngFor="let job of recommendedJobs"><span>{{ job.state }}</span><strong>{{ job.title }}</strong><small>{{ job.department }} · {{ job.salary }}</small></div>
        </article>
        <article class="glass">
          <h3>Applications & Fees</h3>
          <div class="mini-feed" *ngFor="let app of applications"><span>{{ app.applicationStatus }}</span><strong>{{ app.title }}</strong><small>Fee {{ app.feeStatus }} · Score {{ app.skillTestScore || 0 }}%</small></div>
          <p *ngIf="!applications.length" class="muted">No applications yet.</p>
        </article>
        <article class="glass" *ngIf="page === 'hr' || page === 'admin'">
          <h3>Recruiter Tools</h3>
          <button class="btn primary" (click)="createJob()">Post Sample Government Job</button>
          <button class="btn secondary" (click)="navigate('connections')">Review Connections</button>
          <button class="btn ghost" (click)="navigate('chat')">Open HR Chat</button>
        </article>
      </div>
    </section>

    <section *ngIf="page === 'skill-test'" class="page">
      <div class="section-title"><p>Online assessment</p><h2>Skill Test</h2></div>
      <div class="test-card glass">
        <div class="question" *ngFor="let q of [1,2,3,4,5]">
          <h3>{{ q }}. {{ ['Indian Constitution was adopted in which year?', 'Which test measures numerical aptitude?', 'RTI Act primarily supports what?', 'Aptitude score is used for?', 'Which body conducts UPSC CSE?'][q-1] }}</h3>
          <label *ngFor="let option of ['A','B','C','D']"><input type="radio" [name]="'q'+q" [(ngModel)]="testAnswers[q]" [value]="option"> {{ option }}</label>
        </div>
        <button class="btn primary" (click)="submitTest()">Submit Test</button>
        <div *ngIf="testResult" class="result-box">Score {{ testResult.score }}/{{ testResult.totalMarks }} · {{ testResult.percentage }}% · {{ testResult.passed ? 'Passed' : 'Needs practice' }}</div>
      </div>
    </section>

    <section *ngIf="page === 'results' || page === 'admit-cards' || page === 'notifications'" class="page">
      <div class="section-title"><p>Exam lifecycle</p><h2>{{ page === 'results' ? 'Result Tracking' : page === 'admit-cards' ? 'Admit Cards' : 'Notifications' }}</h2></div>
      <div class="dashboard-grid">
        <article class="glass" *ngFor="let job of jobs.slice(0, 6)">
          <span class="tag">{{ job.state }}</span>
          <h3>{{ job.title }}</h3>
          <p *ngIf="page === 'results'">Result expected after {{ job.examStartDate | date:'mediumDate' }}. Status: merit list under review.</p>
          <p *ngIf="page === 'admit-cards'">Admit card window opens before exam date. Center allocation: pending.</p>
          <p *ngIf="page === 'notifications'">Application deadline {{ job.applicationDeadline | date:'mediumDate' }}. Fee ₹{{ job.applicationFee }}.</p>
        </article>
      </div>
    </section>

    <section *ngIf="page === 'resume'" class="page detail-grid">
      <div class="glass">
        <div class="section-title left"><p>Resume builder</p><h2>Build ATS-ready profile</h2></div>
        <textarea [(ngModel)]="resume.headline"></textarea>
        <textarea [(ngModel)]="resume.education"></textarea>
        <textarea [(ngModel)]="resume.skills"></textarea>
        <textarea [(ngModel)]="resume.experience"></textarea>
      </div>
      <div class="resume-preview glass">
        <h2>{{ user?.firstName || 'Candidate' }} {{ user?.lastName || 'Profile' }}</h2>
        <p>{{ resume.headline }}</p><h3>Education</h3><p>{{ resume.education }}</p><h3>Skills</h3><p>{{ resume.skills }}</p><h3>Experience</h3><p>{{ resume.experience }}</p>
      </div>
    </section>

    <section *ngIf="page === 'connections'" class="page">
      <div class="section-title"><p>LinkedIn-style networking</p><h2>Connection Requests</h2></div>
      <button class="btn primary" (click)="requestConnection()">Request HR Guidance</button>
      <div class="dashboard-grid mt-6"><article class="glass" *ngFor="let c of connections"><span class="tag">{{ c.status }}</span><h3>{{ c.hrName || c.userName }}</h3><p>{{ c.requestMessage }}</p></article></div>
    </section>

    <section *ngIf="page === 'chat'" class="page">
      <div class="section-title"><p>Socket-ready messaging</p><h2>Real-time HR Chat</h2></div>
      <div class="chat-box glass">
        <div class="message" *ngFor="let msg of messages" [class.mine]="msg.senderId === user?.id"><b>{{ msg.senderName }}</b><p>{{ msg.message }}</p><small>{{ msg.createdAt | date:'short' }}</small></div>
        <div class="chat-input"><input [(ngModel)]="chatText" placeholder="Message HR recruiter..." (keyup.enter)="sendMessage()"><button class="btn primary" (click)="sendMessage()">Send</button></div>
      </div>
    </section>
  </div>
</main>
